-- Pallof Press Eccentric Return (pallof-press-eccentric-return)
UPDATE coaching.exercise SET
  name = 'Pallof Press Eccentric Return',
  description = 'Pallof Press Eccentric Return is a slow negative/eccentric drill for anti-rotation eccentric control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.',
  card_summary = 'Pallof Press Eccentric Return builds anti-rotation eccentric control through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.',
  coach_language = 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 4-6 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: anti-rotation eccentric control.',
