  movement_family = 'Anti-rotation eccentric return',
  primary_phase_key = 'resilience',
  phase_subrole = 'slow_eccentric_isometric_joint_resilience',
  primary_order_slot = 'pallof_press_eccentric_return',
  default_sets = 2,
  default_reps = 6,
  default_work_seconds = 36,
  default_rest_seconds = 60,
  est_seconds_per_set = 96,
  movement_requirements = '{"primary_joint_actions":["anti_rotation_press","eccentric_rotation_control","shoulder_protraction_retraction","trunk_bracing"],"primary_tissues":["obliques","abdominals","glutes","shoulder_stabilizers"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0,"prerequisites":["Pain-free basic pattern for Pallof Press Eccentric Return","Ability to stop the set before alignment breaks","No acute flare-up in the target tissue or joint"],"quality_threshold":"Stop or regress if alignment, breathing, tempo, range control, or pain-free execution breaks down.","joint_resilience_profile":{"target":"anti-rotation eccentric control","primary_strategy":"Controlled eccentric / negative lowering in pain-free owned range.","tempo_target":"4-6 seconds","range_emphasis":"Use the largest range the athlete can own without compensation.","progression_trigger":"Progress only when target tissue tolerates the dose with clean alignment and normal recovery within 24-48 hours."}}'::jsonb,
  coaching_execution = '{"movement_description":"Pallof Press Eccentric Return is a slow negative/eccentric drill for anti-rotation eccentric control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Stand perpendicular to a band/cable anchor in an athletic stance.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo or volume."],"execution_steps":["Create tension and start from a position the athlete can own.","Press out, hold briefly, then return the hands toward the chest for 4 seconds without rotating.","Keep breathing controlled and avoid bouncing, dropping, twisting, or rushing the last third of the range.","Reset each rep so the next negative starts from the same clean position."],"coach_cues":["Slow is the load.","Own the last third.","Stop before compensation.","Quiet breath, quiet joints."],"athlete_cues":["Move like you could pause anywhere.","Control the down, reset the up.","No pain, no collapse."],"breathing_cues":["Inhale before the rep if needed, then exhale slowly through the lowering phase.","Do not use breath holding to hide loss of position."],"common_faults":["Rushing the negative after the first half of the range.","Adding load before the athlete owns tempo and alignment.","Turning a tissue-control drill into a fatigue circuit.","Pushing through pain, joint pinch, or visible collapse."],"quality_gate":["Tempo stays within the prescribed range.","Target joint line stays clean with no uncontrolled wobble or collapse.","Athlete finishes the set with the same posture and range they started with.","No pain response during the set or unusual next-day flare-up."],"stop_signs":["Sharp pain, cramping that changes mechanics, numbness, dizziness, or joint pinch.","Tempo cannot be maintained for the planned range.","Breath holding, shaking, or compensation becomes the main strategy."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Restore / cooldown breathing","Low-intensity mobility for the trained region","Non-fatiguing skill review"],"pairs_well_after":["General warm-up and mobility access","Main strength pattern for the same region","Low-level technical patterning that does not fatigue the target tissue"],"good_for_sessions":["resilience","tissue_capacity","general_warmup"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Acute pain or recent flare-up in the target joint or tissue","Athlete cannot control the simpler version pain-free","The next session block requires maximal sprint, jump, cutting, throwing, or high-skill freshness","The athlete is too fatigued to maintain tempo and alignment"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex slow-eccentric demo recommended","Vortex Exercise Card Authoring Guide: Resilience / slow eccentric-isometric joint resilience","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Pallof Press Eccentric Return from front and side where useful.","Show one regression, one standard version, and one progression.","Emphasize that tempo, range, and weekly dose are programming variables.","Eccentric negative training cluster card; source: eccentric_negative_training_cards_all_50."]}'::jsonb,
