  gender_specific_notes = CASE WHEN 'youth_intermediate' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('slow-eccentric-split-squat', 'Use the same exercise with a modest tempo target, usually 3-4 seconds down. Progress range before load.', 'No default gender-specific adjustment. Individualize by training age, tissue history, joint symptoms, recovery response, pelvic-floor symptoms when relevant, footwear, surface, and fatigue state.'),
