UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'teen' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('slow-eccentric-split-squat', 'Use after technical or output work, not as a fatigue finisher. Keep reps low and require repeatable alignment.', 'No default gender-specific adjustment. Individualize by training age, tissue history, joint symptoms, recovery response, pelvic-floor symptoms when relevant, footwear, surface, and fatigue state.'),
