UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'adult_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
