);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Builds tissue tolerance, joint ownership, and braking control through deliberate negative-phase loading in the Resilience phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('slow-eccentric-split-squat', 'Slow eccentrics create time under tension while the athlete must organize joints, breathing, and posture. For Slow Eccentric Split Squat, the slower lower makes compensations obvious and gives the coach time to adjust range, load, or support before pain or collapse.', 'Belongs in Resilience / Slow Eccentric-Isometric Joint Resilience because the goal is tissue tolerance, joint ownership, and braking control after higher-priority speed, power, skill, or strength work.', 'Use in the Resilience phase after Output and main Capacity work, or as a low-volume accessory after the main pattern. Harder eccentric tissue stress should not be placed before sprinting, jumping, cutting, or high-skill work.', 'Do not treat hard negatives as a daily warm-up or conditioning finisher. Avoid placing heavy hamstring, calf, groin, shoulder, elbow, or knee eccentrics before explosive Output when spring, speed, or skill quality matters.', 'Scale by reducing range, tempo, load, lever length, instability, impact, or weekly frequency before accepting pain, shaking, breath holding, or position loss.'),
