)
VALUES (
  'validation_rule',
  'eccentric_negative_training_readiness',
  NULL,
  'Eccentric / negative training without wrong phase intent or pre-fatigue',
  'Deliberate negative-phase Resilience work must use controlled tempo, pain-free range, and adequate rest — not daily warm-ups, conditioning finishers, or pre-sprint tissue stress.',
  'Eccentric negative training cards span lower-body knee/hip control, posterior-chain and lower-leg tissue capacity, upper-body pull/push negatives, trunk/bracing/landing deceleration, and loaded tempo machine/cable negatives for Resilience-phase joint ownership.',
  'Slow eccentrics build tissue tolerance and braking control when dosed after Output and main Capacity. Poor placement, short rest, or mis-tagged fatigue work steals freshness from speed, jumping, and skill quality.',
  'Place after Output and main Capacity in the same session; coach 4–6 second lowers with full rest between sets; progress range, load, or tempo one variable at a time only when alignment and recovery stay clean.',
  'Do not program hard hamstring, calf, groin, shoulder, or knee negatives before explosive Output; do not chase volume when tempo, alignment, or pain flags degrade.'
)
